import React, { useEffect, useState } from "react";
import axios from "axios";

const Summary = () => {
  const [holdings, setHoldings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchHoldings = async () => {
      try {
        const res = await axios.get(
          `${process.env.REACT_APP_API_URL || "http://localhost:3002"}/allHoldings`
        );
        setHoldings(res.data);
      } catch (err) {
        console.error("Failed to fetch holdings:", err);
        setError("Failed to load summary data.");
      } finally {
        setLoading(false);
      }
    };

    fetchHoldings();
  }, []);

  const totalInvestment = holdings.reduce(
    (acc, stock) => acc + stock.avg * stock.qty,
    0
  );

  const totalCurrentValue = holdings.reduce(
    (acc, stock) => acc + stock.price * stock.qty,
    0
  );

  const totalPnL = totalCurrentValue - totalInvestment;
  const totalPnLPercent =
    totalInvestment > 0 ? (totalPnL / totalInvestment) * 100 : 0;

  const formatCurrency = (value) =>
    value.toLocaleString("en-IN", {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    });

  if (loading) return <p>Loading summary...</p>;
  if (error) return <p className="error">{error}</p>;

  return (
    <>
      <h3 className="title">Portfolio Summary</h3>

      <div className="summary-container">
        <div className="summary-box">
          <h5>₹{formatCurrency(totalInvestment)}</h5>
          <p>Total Investment</p>
        </div>

        <div className="summary-box">
          <h5>₹{formatCurrency(totalCurrentValue)}</h5>
          <p>Current Value</p>
        </div>

        <div className="summary-box">
          <h5 className={totalPnL >= 0 ? "profit" : "loss"}>
            ₹{formatCurrency(totalPnL)} ({totalPnLPercent.toFixed(2)}%)
          </h5>
          <p>Total P&L</p>
        </div>
      </div>

      <h4>Holdings</h4>

      <table>
        <thead>
          <tr>
            <th>Stock</th>
            <th>Qty</th>
            <th>Avg</th>
            <th>LTP</th>
            <th>P&L</th>
          </tr>
        </thead>

        <tbody>
          {holdings.map((stock) => {
            const pnl = stock.price * stock.qty - stock.avg * stock.qty;

            return (
              <tr key={stock.name}>
                <td>{stock.name}</td>
                <td>{stock.qty}</td>
                <td>₹{formatCurrency(stock.avg)}</td>
                <td>₹{formatCurrency(stock.price)}</td>
                <td className={pnl >= 0 ? "profit" : "loss"}>
                  ₹{formatCurrency(pnl)}
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </>
  );
};

export default Summary;
